import axios from 'axios';

const backendURL = 'http://localhost:3000/api/exams';

// Get authorization header
const getAuthHeader = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: token } : {};
};

// Get all exams
export const getAllExams = async () => {
    try {
        const response = await axios.get(backendURL);
        return response.data;
    } catch (error) {
        console.error('Get all exams error:', error);
        throw error;
    }
};

// Create a new exam
export const createExam = async (examData) => {
    try {
        const response = await axios.post(backendURL, examData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Create exam error:', error);
        throw error;
    }
};

// Get exam by ID
export const getExam = async (id) => {
    try {
        const response = await axios.get(`${backendURL}/${id}`);
        return response.data;
    } catch (error) {
        console.error('Get exam error:', error);
        throw error;
    }
};

// Update exam
export const updateExam = async (id, examData) => {
    try {
        const response = await axios.put(`${backendURL}/${id}`, examData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Update exam error:', error);
        throw error;
    }
};

// Delete exam
export const deleteExam = async (id) => {
    try {
        const response = await axios.delete(`${backendURL}/${id}`, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Delete exam error:', error);
        throw error;
    }
};

// Submit exam
export const submitExam = async (examData) => {
    try {
        const response = await axios.post(`${backendURL}/submit`, examData, {
            headers: getAuthHeader()
        });
        return response.data;
    } catch (error) {
        console.error('Submit exam error:', error);
        throw error;
    }
};

// Get exams by difficulty
export const getExamsByDifficulty = async (difficulty) => {
    try {
        const response = await axios.get(`${backendURL}/difficulty/${difficulty}`);
        return response.data;
    } catch (error) {
        console.error('Get exams by difficulty error:', error);
        throw error;
    }
};

// Get exams by subject
export const getExamsBySubject = async (subjectId) => {
    try {
        const response = await axios.get(`${backendURL}/subject/${subjectId}`);
        return response.data;
    } catch (error) {
        console.error('Get exams by subject error:', error);
        throw error;
    }
};
